module counter5bit_inc3 (
    input clk,
    input rst,
    input en,
    output [4:0] q
);

    reg [4:0] q_reg;

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge rst or posedge dbg_halt) begin
        if (rst)
            q_reg <= 5'b0;
        else if (en)
            q_reg <= q_reg + 3;
    end

    assign q = q_reg;

endmodule
